VALUES
  ('optician-moex-00729', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有一受測者自覺式驗光結果為-1.00DS/-1.00DC×180，其角膜弧度儀檢查結果為44.50D@180/46.00D@090， 則眼內所殘餘的散光值為何？', '["-0.50DC×180", "-1.00DC×180", "+0.50DC×180", "+1.00DC×180"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00730', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '阿德目前試戴的硬式隱形眼鏡試片規格：基弧7.80mm/-4.50D視力檢查1.0，使用螢光染色檢查發現頂端 接觸（apicalbearing），最後訂片建議何者最合適？', '["7.70mm/-5.00D", "7.70mm/-4.00D", "7.90mm/-5.00D", "7.90mm/-4.00D"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00731', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有一受測者配戴度數為-3.00DS，基弧為7.90mm之RGP隱形眼鏡後，以螢光染劑評估配戴之鬆緊度，結 果觀察到鏡片中央有螢光蓄積（pooling）之現象，若不調整鏡片直徑而只改變基弧的狀況下更換新的RGP 鏡片，以達到適當之鬆緊度，則下列何者可能為新的RGP鏡片之規格？', '["-3.50DS/8.00mm", "-2.50DS/8.00mm", "-3.50DS/7.80mm", "-2.50DS/7.80mm"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00732', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '以球面硬式隱形眼鏡初次驗配時，若水平虹膜直徑（HVID）為11.8mm，眼裂大小10.8mm，則須選用多 大之試片？', '["8.6mm", "9.2mm", "9.6mm", "10.0mm"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00733', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於使用單眼視覺法（monovision）為病人驗配隱形眼鏡，下列何者正確？', '["選用此方法來治療老花者慢慢增加，因為比較不易出現像多焦點隱形眼鏡可能出現的鬼影或是視力不穩 定的現象", "不管是高對比、低對比視力都比硬式多焦點隱形眼鏡和軟式雙焦點隱形眼鏡好，只是需要一段時間適應", "病人如是內向男性比較容易驗配成功，因為會更努力去適應", "驗配成功率達七到八成左右"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00734', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '關於軟式隱形眼鏡戴起來過鬆（loosefit）的敘述，下列何者錯誤？', '["戴起來不舒服", "眨眼時鏡片滑動至少超過0.5mm", "上推鏡片時較不容易移位", "鏡片邊緣容易翹起，尤其在下緣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00735', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關最佳的硬式隱形眼鏡驗配，下列敘述何者錯誤？', '["當眼睛睜開時，良好的鏡片配適鏡片定位會置中", "鏡片光學區可以完全覆蓋瞳孔", "在與眼瞼的互動情況下，鏡片邊緣將位於上眼瞼下方", "硬式鏡片設計較厚的邊緣並結合負載體（negativecarrier），也無利於鏡片的定位"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00736', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列那一個眼睛參數是決定軟式隱形眼鏡直徑的最重要參考？', '["角膜最平K值", "角膜直徑", "角膜散光", "瞳孔直徑"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00737', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列何者不是因透氣硬式隱形眼鏡（RGPlens）鏡片中心厚度太厚而造成的常見現象？', '["鏡片較易變形", "較易往下偏位", "視力不穩定", "眼角膜乾燥"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00738', 'optician', 'optician-moex-111-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '一位戴著硬式隱形眼鏡的患者，目前使用的鏡片規格如下：基弧44.25D、度數-6.25DS、直徑9.0mm、光 心7.8mm。但是，這鏡片戴在患者眼睛上出現明顯的鼻側位移，視力可達1.2，可是需要改訂以下的處方 才能改善鼻側位移的現象，更改的處方為：基弧44.75D、直徑9.5mm、光心8.2mm，這時更改處方後所 需要的鏡片度數為何？', '["-6.00DS", "-6.25DS", "-6.50DS", "-6.75DS"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "e675a5a5fb53", "answer_pdf_sha1": "f683e60a8b21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "112", "s": "1008", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
